1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const FP_EPSILON = 1e-9;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string; cursed?: boolean; enchantment?: number };
13	type Customer = { yearsWithMHPCO: number };
14	type Damage = { itemType: string; amount: number };
15	type Incident = { cause: string; damages: Damage[] };
16	type QuoteStep = { op: "quote"; items: Item[] };
17	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
18	type Step = QuoteStep | ClaimStep;
19	type Scenario = { customer: Customer; steps: Step[] };
20	
21	const DEDUCTIBLE = 100;
22	const INSURANCE_VALUE: Record<string, number> = {
23	  sword: 1000,
24	  amulet: 600,
25	  rune: 250,
26	  moonstone: 250,
27	};
28	const CAP_MULTIPLIER = 2;
29	
30	const sum = (numbers: number[]): number =>
31	  numbers.reduce((acc, n) => acc + n, 0);
32	
33	// round up to whole G in MHPCO's favor, using epsilon to fight FP error
34	const roundUpInMHPCOFavor = (amount: number): number =>
35	  Math.ceil(amount - FP_EPSILON);
36	
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	const COMPONENT_BLOCK_SIZE = 3;
39	const COMPONENT_BLOCK_PRICE = 60;
40	
41	const countByType = (items: Item[]): Map<string, number> =>
42	  items.reduce(
43	    (acc, item) => acc.set(item.type, (acc.get(item.type) ?? 0) + 1),
44	    new Map<string, number>(),
45	  );
46	
47	const typeGroupPremium = (type: string, count: number): number =>
48	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE
49	    ? COMPONENT_BLOCK_PRICE
50	    : count * BASE_PREMIUM[type];
51	
52	const itemsBasePremium = (items: Item[]): number =>
53	  sum(
54	    Array.from(countByType(items), ([type, count]) =>
55	      typeGroupPremium(type, count),
56	    ),
57	  );
58	
59	type Rule<T> = { applies: (subject: T) => boolean; rate: number };
60	
61	const applicableRatesTotal = <T>(base: number, subject: T, rules: Rule<T>[]): number =>
62	  sum(rules.map((rule) => (rule.applies(subject) ? base * rule.rate : 0)));
63	
64	const CURSE_SURCHARGE_RATE = 0.5;
65	const HIGH_ENCHANTMENT_RATE = 0.3;
66	const HIGH_ENCHANTMENT_THRESHOLD = 5;
67	
68	const SURCHARGE_RULES: Rule<Item>[] = [
69	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE_RATE },
70	  {
71	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
72	    rate: HIGH_ENCHANTMENT_RATE,
73	  },
74	];
75	
76	const itemSurcharge = (item: Item): number =>
77	  applicableRatesTotal(BASE_PREMIUM[item.type], item, SURCHARGE_RULES);
78	
79	const itemSurcharges = (items: Item[]): number =>
80	  sum(items.map(itemSurcharge));
81	
82	const LOYALTY_DISCOUNT_RATE = 0.2;
83	const LOYALTY_YEARS_THRESHOLD = 2;
84	const FOLLOWUP_DISCOUNT_RATE = 0.15;
85	
86	type PolicyContext = { customer: Customer; isFollowup: boolean };
87	
88	const POLICY_MODIFIER_RULES: Rule<PolicyContext>[] = [
89	  { applies: () => true, rate: FIRST_INSURANCE_RATE },
90	  {
91	    applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
92	    rate: -LOYALTY_DISCOUNT_RATE,
93	  },
94	  { applies: (ctx) => ctx.isFollowup, rate: -FOLLOWUP_DISCOUNT_RATE },
95	];
96	
97	const policyModifiers = (policyBase: number, ctx: PolicyContext): number =>
98	  applicableRatesTotal(policyBase, ctx, POLICY_MODIFIER_RULES);
99	
100	const assertKnownItemType = (item: Item): void => {
101	  if (!(item.type in BASE_PREMIUM)) {
102	    throw new Error(`unknown item type: ${item.type}`);
103	  }
104	};
105	
106	const quote = ({ items }: QuoteStep, ctx: PolicyContext): { premium: number } => {
107	  items.forEach(assertKnownItemType);
108	  const policyBase = itemsBasePremium(items);
109	  const total =
110	    policyBase +
111	    itemSurcharges(items) +
112	    policyModifiers(policyBase, ctx) +
113	    PROCESSING_FEE;
114	  return { premium: roundUpInMHPCOFavor(total) };
115	};
116	
117	type Policy = { items: Item[]; remainingCap: number };
118	
119	const policyInsuranceSum = (items: Item[]): number =>
120	  sum(items.map((item) => INSURANCE_VALUE[item.type]));
121	
122	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
123	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
124	const FULL_PAYOUT_RATE = 1;
125	
126	const payoutRate = (item: Item): number =>
127	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
128	    ? HIGH_ENCHANTMENT_PAYOUT_RATE
129	    : FULL_PAYOUT_RATE;
130	
131	const damagePayout = (damage: Damage, item: Item): number =>
132	  Math.max(0, damage.amount * payoutRate(item) - DEDUCTIBLE);
133	
134	const openPolicy = (items: Item[]): Policy => ({
135	  items,
136	  remainingCap: policyInsuranceSum(items) * CAP_MULTIPLIER,
137	});
138	
139	const processQuote = (
140	  step: QuoteStep,
141	  customer: Customer,
142	  policies: Policy[],
143	) => {
144	  const result = quote(step, { customer, isFollowup: policies.length > 0 });
145	  policies.push(openPolicy(step.items));
146	  return result;
147	};
148	
149	const findInsuredItem = (policy: Policy, itemType: string): Item =>
150	  policy.items.find((i) => i.type === itemType) as Item;
151	
152	const uncappedClaimPayout = (policy: Policy, incident: Incident): number =>
153	  sum(incident.damages.map((d) => damagePayout(d, findInsuredItem(policy, d.itemType))));
154	
155	const processClaim = (step: ClaimStep, policies: Policy[]) => {
156	  const policy = policies[step.policy];
157	  const payout = Math.min(uncappedClaimPayout(policy, step.incident), policy.remainingCap);
158	  policy.remainingCap -= payout;
159	  return { payout, remainingCap: policy.remainingCap };
160	};
161	
162	export const runScenario = (input: unknown): unknown => {
163	  const { customer, steps } = input as Scenario;
164	  const policies: Policy[] = [];
165	  const results = steps.map((step) =>
166	    step.op === "quote"
167	      ? processQuote(step, customer, policies)
168	      : processClaim(step, policies),
169	  );
170	  return { results };
171	};
